/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesTable, buttonUpdateInvoice), FormControlEventType::Clicked)]
public static void buttonUpdateInvoice_OnClicked(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableSalesInvoiceWorkflow == NoYes::Yes)
    {
        SalesTable SalesTable = sender.formRun().datasource(1).cursor();
        ETGSalesEditLines etgsaleseditlines;
        SalesParmLine salesparmline;

        select sum(Quantity) from etgsaleseditlines
        where etgsaleseditlines.SalesId == SalesTable.SalesId
        && etgsaleseditlines.WorkflowStatus == ETGSalesEditLinesWorkflow::Approved;

        ttsbegin;
        select forupdate salesparmline
        where salesparmline.OrigSalesId == etgsaleseditlines.SalesId;
        if(salesparmline)
        {
            salesparmline.DeliverNow = etgsaleseditlines.Quantity;
            salesparmline.update();
        }
        ttscommit;
    }
}
